test('EXPLORE-001: Home — capture h1, p, link text, bg, absence of header/nav/footer', async ({ page }) => {
  await page.goto(BASE_URL, { waitUntil: 'networkidle' });
  await page.screenshot({ path: path.join(SCREENSHOT_DIR, 'home.png'), fullPage: true });

  const h1Text = await page.locator('h1').textContent();
  console.log('h1:', h1Text);

  const pText = await page.locator('p').first().textContent();
  console.log('p:', pText);

  // Try "Learn more" first, then "More information"
  const learnMore = page.locator('a:has-text("Learn more")');
  const moreInfo  = page.locator('a:has-text("More information")');
  const learnMoreVisible = await learnMore.isVisible().catch(() => false);
  const moreInfoVisible  = await moreInfo.isVisible().catch(() => false);
  console.log('Link "Learn more" visible:', learnMoreVisible);
  console.log('Link "More information" visible:', moreInfoVisible);

  // Link href
  const linkSelector = learnMoreVisible ? 'a:has-text("Learn more")' : 'a:has-text("More information")';
  const href = await page.locator(linkSelector).getAttribute('href');
  console.log('Link href:', href);

  // Target attribute — same tab or new tab?
  const target = await page.locator(linkSelector).getAttribute('target');
  console.log('Link target:', target);

  // Background colour
  const bg = await page.evaluate(() => getComputedStyle(document.body).backgroundColor);
  console.log('Body bg:', bg);

  // Absence of structural elements
  const headerCount = await page.locator('header').count();
  const navCount    = await page.locator('nav').count();
  const footerCount = await page.locator('footer').count();
  console.log('header count:', headerCount, '| nav count:', navCount, '| footer count:', footerCount);
});

